import{_ as e,o as l,c as r,a2 as a}from"./chunks/framework.DnrXFDHb.js";const x=JSON.parse('{"title":"文曄科技（WT Microelectronics）深度研究","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/IC通路商研究/文曄科技深度研究.md","filePath":"Deep32Q知識庫/產業洞察/IC通路商研究/文曄科技深度研究.md"}'),n={name:"Deep32Q知識庫/產業洞察/IC通路商研究/文曄科技深度研究.md"};function i(d,t,s,o,g,h){return l(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="文曄科技-wt-microelectronics-深度研究" tabindex="-1">文曄科技（WT Microelectronics）深度研究 <a class="header-anchor" href="#文曄科技-wt-microelectronics-深度研究" aria-label="Permalink to &quot;文曄科技（WT Microelectronics）深度研究&quot;">​</a></h1><p><strong>股票代號：</strong> 3036 <strong>更新日期：</strong> 2026-05-12</p><hr><h2 id="_1-公司基本資料" tabindex="-1">1. 公司基本資料 <a class="header-anchor" href="#_1-公司基本資料" aria-label="Permalink to &quot;1. 公司基本資料&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">項目</th><th style="text-align:left;">內容</th></tr></thead><tbody><tr><td style="text-align:left;">公司名稱</td><td style="text-align:left;">文曄科技股份有限公司（WT Microelectronics Taiwan）</td></tr><tr><td style="text-align:left;">股票代號</td><td style="text-align:left;">3036（TWSE）</td></tr><tr><td style="text-align:left;">總部</td><td style="text-align:left;">台北 + 蒙特婁（雙總部架構，併購 Future 後）</td></tr><tr><td style="text-align:left;">全球據點</td><td style="text-align:left;">48 國、160+ 辦公室</td></tr><tr><td style="text-align:left;">客戶數量</td><td style="text-align:left;">全球超過 25,000 家</td></tr><tr><td style="text-align:left;">供應商數量</td><td style="text-align:left;">400+ 家主要技術領域供應商</td></tr><tr><td style="text-align:left;">全球排名</td><td style="text-align:left;">Gartner 2024 年全球第一，市佔率 ~12-14%</td></tr></tbody></table><hr><h2 id="_2-歷史沿革與關鍵里程碑" tabindex="-1">2. 歷史沿革與關鍵里程碑 <a class="header-anchor" href="#_2-歷史沿革與關鍵里程碑" aria-label="Permalink to &quot;2. 歷史沿革與關鍵里程碑&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">時間</th><th style="text-align:left;">事件</th></tr></thead><tbody><tr><td style="text-align:center;">1980s</td><td style="text-align:left;">文曄成立，專注台灣市場電子元件分銷</td></tr><tr><td style="text-align:center;">2018-2023</td><td style="text-align:left;">持續擴張代理產品線，累積技術能力</td></tr><tr><td style="text-align:center;"><strong>2024.04</strong></td><td style="text-align:left;"><strong>完成併購 Future Electronics（38 億美元）— 台灣科技業史上最大海外併購案之一</strong></td></tr><tr><td style="text-align:center;">2024 全年</td><td style="text-align:left;">營收突破兆元，成為台灣第 6 家兆元企業（1.18 兆）</td></tr><tr><td style="text-align:center;">2026 Q1</td><td style="text-align:left;">營收 4,943 億（+100% YoY），EPS 5.32 元創單季新高</td></tr></tbody></table><hr><h2 id="_3-併購-future-electronics-核心故事" tabindex="-1">3. 併購 Future Electronics（核心故事） <a class="header-anchor" href="#_3-併購-future-electronics-核心故事" aria-label="Permalink to &quot;3. 併購 Future Electronics（核心故事）&quot;">​</a></h2><h3 id="_3-1-併購概要" tabindex="-1">3.1 併購概要 <a class="header-anchor" href="#_3-1-併購概要" aria-label="Permalink to &quot;3.1 併購概要&quot;">​</a></h3><ul><li><strong>時間：</strong> 2024 年 4 月 2 日正式完成</li><li><strong>金額：</strong> 38 億美元</li><li><strong>Future Electronics 背景：</strong> 加拿大電子元件通路商，全球前十、專注歐美市場</li><li><strong>併購後影響：</strong> 文曄從區域性通路商躍升為全球第一</li></ul><h3 id="_3-2-併購後整合成果" tabindex="-1">3.2 併購後整合成果 <a class="header-anchor" href="#_3-2-併購後整合成果" aria-label="Permalink to &quot;3.2 併購後整合成果&quot;">​</a></h3><ul><li>全球據點擴至 <strong>48 國、160+ 辦公室</strong></li><li>供應商網絡擴展至 <strong>400+ 家</strong>主要技術領域供應商</li><li>客戶覆蓋全球超過 <strong>25,000 家</strong></li><li>Gartner 全球市佔率從併購前的區域排名躍升至 <strong>全球第一（~12-14%）</strong></li><li>台北 + 蒙特婁雙總部營運架構</li></ul><blockquote><p>來源：Gartner、中央社（2024-04-03）、文曄官網</p></blockquote><hr><h2 id="_4-代理產品線-半導體明星隊" tabindex="-1">4. 代理產品線（半導體明星隊） <a class="header-anchor" href="#_4-代理產品線-半導體明星隊" aria-label="Permalink to &quot;4. 代理產品線（半導體明星隊）&quot;">​</a></h2><p>文曄代理超過 400 家供應商，核心品牌包括：</p><table tabindex="0"><thead><tr><th style="text-align:left;">類別</th><th style="text-align:left;">主要代理品牌</th></tr></thead><tbody><tr><td style="text-align:left;">CPU/GPU</td><td style="text-align:left;">Intel、AMD、Broadcom、Marvell</td></tr><tr><td style="text-align:left;">行動晶片</td><td style="text-align:left;">Qualcomm、聯發科（MediaTek）</td></tr><tr><td style="text-align:left;">類比/混合訊號</td><td style="text-align:left;">NXP、Microchip、TI（德州儀器）</td></tr><tr><td style="text-align:left;">記憶體</td><td style="text-align:left;">Micron、Samsung</td></tr><tr><td style="text-align:left;">網路/通訊</td><td style="text-align:left;">Broadcom、Marvell</td></tr></tbody></table><hr><h2 id="_5-營收結構-2026-q1" tabindex="-1">5. 營收結構（2026 Q1） <a class="header-anchor" href="#_5-營收結構-2026-q1" aria-label="Permalink to &quot;5. 營收結構（2026 Q1）&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">應用領域</th><th style="text-align:center;">佔比</th><th style="text-align:center;">年增率</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>資料中心</strong></td><td style="text-align:center;"><strong>56.8%</strong></td><td style="text-align:center;"><strong>+248% YoY</strong></td></tr><tr><td style="text-align:left;">通訊</td><td style="text-align:center;">~12%</td><td style="text-align:center;">—</td></tr><tr><td style="text-align:left;">工業</td><td style="text-align:center;">~15-18%</td><td style="text-align:center;">穩健復甦</td></tr><tr><td style="text-align:left;">車用及其他</td><td style="text-align:center;">~15-18%</td><td style="text-align:center;">—</td></tr></tbody></table><p><strong>關鍵洞察：</strong></p><ul><li>資料中心佔比從約 33% 一年內翻倍至 57%，AI 伺服器需求是核心驅動力</li><li>AI 產品雖毛利率較低，但營收規模與絕對獲利暴增</li></ul><hr><h2 id="_6-財務分析" tabindex="-1">6. 財務分析 <a class="header-anchor" href="#_6-財務分析" aria-label="Permalink to &quot;6. 財務分析&quot;">​</a></h2><h3 id="_6-1-2026-q1-財報重點" tabindex="-1">6.1 2026 Q1 財報重點 <a class="header-anchor" href="#_6-1-2026-q1-財報重點" aria-label="Permalink to &quot;6.1 2026 Q1 財報重點&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">項目</th><th style="text-align:center;">數據</th><th style="text-align:center;">備註</th></tr></thead><tbody><tr><td style="text-align:left;">合併營收</td><td style="text-align:center;"><strong>4,943 億</strong>（新台幣）</td><td style="text-align:center;">季增 ~44%、年增 <strong>~100%</strong>，超越財測高標</td></tr><tr><td style="text-align:left;">EPS</td><td style="text-align:center;"><strong>5.32 元</strong></td><td style="text-align:center;">季增 ~54%、年增 ~120%，創單季 EPS 歷史新高</td></tr><tr><td style="text-align:left;">毛利率</td><td style="text-align:center;"><strong>3.45%</strong></td><td style="text-align:center;">較 Q4 的 3.74% 及去年同期 4.58% 略低，但仍優於財測預期</td></tr><tr><td style="text-align:left;">營業利益率</td><td style="text-align:center;"><strong>2.01%</strong></td><td style="text-align:center;">季增 +2.6ppt</td></tr><tr><td style="text-align:left;">存貨天數</td><td style="text-align:center;"><strong>50 天</strong></td><td style="text-align:center;">庫存去化與資金運用效率同步優化</td></tr><tr><td style="text-align:left;">營業現金週轉</td><td style="text-align:center;"><strong>21 天</strong></td><td style="text-align:center;">營運效率改善</td></tr></tbody></table><h3 id="_6-2-2025-全年" tabindex="-1">6.2 2025 全年 <a class="header-anchor" href="#_6-2-2025-全年" aria-label="Permalink to &quot;6.2 2025 全年&quot;">​</a></h3><ul><li>營收：<strong>1.18 兆新台幣</strong>（年增 ~23%），首次突破兆元大關</li><li>成為台灣第 6 家兆元企業</li></ul><h3 id="_6-3-2026-q2-財測" tabindex="-1">6.3 2026 Q2 財測 <a class="header-anchor" href="#_6-3-2026-q2-財測" aria-label="Permalink to &quot;6.3 2026 Q2 財測&quot;">​</a></h3><ul><li>營收預估：<strong>5,600-5,900 億</strong>（新台幣）</li><li>EPS 預估：<strong>6.03-6.78 元</strong></li></ul><h3 id="_6-4-風險提示" tabindex="-1">6.4 風險提示 <a class="header-anchor" href="#_6-4-風險提示" aria-label="Permalink to &quot;6.4 風險提示&quot;">​</a></h3><ul><li><strong>負債比攀升：</strong> 目前約 497%，併購 Future 的財務槓桿持續影響</li><li><strong>毛利率下滑趨勢：</strong> 從 2025 Q4 的 3.74% 降至 2026 Q1 的 3.45%，AI 高單價產品拉低毛利率但絕對獲利增加</li><li><strong>「獲利換位」策略：</strong> 犧牲毛利率，追求整體獲利絕對值增加</li></ul><blockquote><p>來源：文曄法說會、中央社、CMoney、財報狗、理財周刊（2026-05-12 搜尋）</p></blockquote><hr><h2 id="_7-策略聯盟與投資布局" tabindex="-1">7. 策略聯盟與投資布局 <a class="header-anchor" href="#_7-策略聯盟與投資布局" aria-label="Permalink to &quot;7. 策略聯盟與投資布局&quot;">​</a></h2><h3 id="_7-1-與祥碩-5269-策略結盟" tabindex="-1">7.1 與祥碩（5269）策略結盟 <a class="header-anchor" href="#_7-1-與祥碩-5269-策略結盟" aria-label="Permalink to &quot;7.1 與祥碩（5269）策略結盟&quot;">​</a></h3><ul><li><strong>時間：</strong> 2020 年 2 月</li><li><strong>方式：</strong> 祥碩以 1 股交換文曄 19 股，互為第二大股東</li><li><strong>目的：</strong> 強化中長期策略關係、化解大聯大非合意收購危機</li><li><strong>綜效：</strong> 祥碩受惠於 AMD 處理器市佔率擴張；文曄認列權益法收益</li></ul><h3 id="_7-2-入股日電貿-3090" tabindex="-1">7.2 入股日電貿（3090） <a class="header-anchor" href="#_7-2-入股日電貿-3090" aria-label="Permalink to &quot;7.2 入股日電貿（3090）&quot;">​</a></h3><ul><li>文曄集團拉高對日電貿持股比重（約 36%）</li><li>從主動元件延伸至<strong>被動元件</strong>領域</li><li>日電貿代理線涵蓋國巨、基美（KEMET）、AVX、Vishay、Panasonic 等全球主要被動元件供應商</li></ul><hr><h2 id="_8-估值與目標價" tabindex="-1">8. 估值與目標價 <a class="header-anchor" href="#_8-估值與目標價" aria-label="Permalink to &quot;8. 估值與目標價&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">項目</th><th style="text-align:center;">數據</th></tr></thead><tbody><tr><td style="text-align:left;">外資目標價（2026）</td><td style="text-align:center;"><strong>288 元</strong></td></tr><tr><td style="text-align:left;">2026 Q1 EPS</td><td style="text-align:center;">5.32 元（創單季新高）</td></tr><tr><td style="text-align:left;">2026 Q2 財測 EPS</td><td style="text-align:center;">6.03-6.78 元</td></tr><tr><td style="text-align:left;">預估全年 EPS（2026）</td><td style="text-align:center;">~21-23 元（推估）</td></tr></tbody></table><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li><strong>Gartner</strong> (2024): 文曄+Future 合併後全球市佔率 ~12-14%，排名世界第一</li><li><strong>中央社</strong> (2024-04-03): 文曄併購 Future Electronics 38 億美元完成</li><li><strong>文曄官網</strong> (2026-05): 全球據點 48 國、160+ 辦公室、400+ 供應商、25,000+ 客戶</li><li><strong>文曄法說會</strong> (2026 Q1): 營收 4,943 億（+100%）、EPS 5.32、毛利率 3.45%、存貨天數 50 天</li><li><strong>CMoney</strong> (2026-05): 文曄 2025 全年營收 1.18 兆、Q1 資料中心佔比 56.8%</li><li><strong>財報狗</strong> (2026-05): 2026 Q2 財測營收 5,600-5,900 億、EPS 6.03-6.78</li><li><strong>理財周刊</strong> (2026): 外資目標價 288 元</li><li><strong>經濟日報</strong> (2020-02): 文曄與祥碩策略結盟詳情</li></ol>',47)])])}const y=e(n,[["render",i]]);export{x as __pageData,y as default};
